import logging
import os

class FilePathContext:
    def __init__(self, path):
        self.filepath = path if isinstance(path, str) else path.filepath
    def open(self, mode):
        return open(self.filepath, mode)

def resolve_format(fmt, filepath):
    _, ext = os.path.splitext(filepath.lower())
    if ext in ['.tsv', '.txt']:
        return 'tsv'
    if ext in ['.yaml', '.yml']:
        return 'yaml'
    return None

def detect_format_by_content(first_line):
    """Detect format from first non-empty line."""
    if '\t' in first_line:
        return 'tsv'
    if ':' in first_line:
        return 'yaml'
    return None

def parse_exchange_table_file(lines):
    """Parse TSV lines. First line is header. Raises ParseError on malformed lines or duplicates."""
    if len(lines) < 2:
        return
    header = lines[0].strip().split('\t')
    if len(header) != 3:
        raise ParseError('TSV header must have exactly 3 fields')
    seen = set()
    for line in lines[1:]:
        parts = line.strip().split('\t')
        if len(parts) != 3:
            raise ParseError('Malformed TSV line: expected 3 tab-separated fields')
        compound = parts[0]
        if compound in seen:
            raise ParseError(f'Duplicate compound: {compound}')
        seen.add(compound)
        yield {'compound': compound, 'lower': float(parts[1]), 'upper': float(parts[2])}

def parse_exchange_yaml_file(lines, default_compartment):
    """Parse YAML-like lines. Raises ParseError on malformed lines or duplicates."""
    if len(lines) < 1:
        return
    seen = set()
    for line in lines:
        parts = line.strip().split(':')
        if len(parts) < 3:
            raise ParseError('Malformed YAML line: expected at least 3 colon-separated fields')
        compound = parts[0]
        if compound in seen:
            raise ParseError(f'Duplicate compound: {compound}')
        seen.add(compound)
        entry = {
            'compound': compound,
            'lower': float(parts[1]),
            'upper': float(parts[2]),
            'compartment': parts[3] if len(parts) > 3 else default_compartment
        }
        yield entry

class ParseError(Exception):
    pass

logger = logging.getLogger(__name__)

def parse_exchange_file(path, default_compartment):
    """Parse a file as a list of exchange compounds with flux limits.

    The file format is detected by content (first non-empty line) when possible;
    if content detection fails, falls back to extension detection.
    Raises ParseError on malformed lines or duplicate compounds.
    """
    context = FilePathContext(path)
    with context.open('r') as f:
        lines = f.readlines()
    # Find first non-empty line for detection
    first_line = None
    for line in lines:
        if line.strip():
            first_line = line.strip()
            break
    if first_line is None:
        # Empty file: no entries
        return

    # Content-based detection
    fmt = detect_format_by_content(first_line)
    if fmt is None:
        # Fall back to extension detection
        fmt = resolve_format(None, context.filepath)
    if fmt is None:
        raise ParseError(f'Unable to detect format of exchange file {context.filepath}')

    if fmt == 'tsv':
        logger.debug('Parsing exchange file %s as TSV', context.filepath)
        yield from parse_exchange_table_file(lines)
    elif fmt == 'yaml':
        logger.debug('Parsing exchange file %s as YAML', context.filepath)
        yield from parse_exchange_yaml_file(lines, default_compartment)
    else:
        raise ParseError(f'Unsupported format: {fmt}')

def main():
    # Create a sample TSV exchange file
    tsv_path = 'exchange_limits.tsv'
    with open(tsv_path, 'w') as f:
        f.write('compound\tlower\tupper\n')
        f.write('Glucose\t-10\t100\n')
        f.write('Lactate\t0\t50\n')

    print('Parsing TSV file:')
    for entry in parse_exchange_file(tsv_path, default_compartment='c'):
        print(entry)

    # Create a sample YAML-like exchange file
    yaml_path = 'exchange_limits.yaml'
    with open(yaml_path, 'w') as f:
        f.write('Glucose:-10:100:cytosol\n')
        f.write('O2:-1000:1000:mitochondria\n')

    print('\nParsing YAML file:')
    for entry in parse_exchange_file(yaml_path, default_compartment='c'):
        print(entry)

if __name__ == '__main__':
    main()
